from pathlib import Path

def find_files(directory: str | Path, extension: str) -> list[Path]:
    root = Path(directory)
    results: list[Path] = []
    ext = extension.lstrip(".")
    try:
        for p in root.rglob(f"*.{ext}"):
            try:
                if p.is_file():
                    results.append(p)
            except PermissionError:
                pass
    except PermissionError:
        pass
    return sorted(results)
```

The outer try/except guards against top-level permission errors; the inner one handles restricted files or symlinks encountered during traversal.

